                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(req)))
                    .andExpect(status().isCreated());
        }

        @Test
        @DisplayName("AC11: username exactly 50 chars is accepted")
        void register_usernameMaxBoundary_returns201() throws Exception {
            String username50 = "a".repeat(50);
            RegisterRequest req = createRegisterRequest(username50, "password123", "Test User");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(req)))
                    .andExpect(status().isCreated());
        }

        // ========== AC12: Password Length Validation ==========

        @Test
        @DisplayName("AC12: password shorter than 8 chars returns 400")
        void register_passwordTooShort_returns400() throws Exception {
            RegisterRequest req = createRegisterRequest("testuser", "short1", "Test User");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
