                    .andExpect(status().isCreated());
        }

        // ========== AC13: DisplayName Validation ==========

        @Test
        @DisplayName("AC13: blank displayName returns 400")
        void register_blankDisplayName_returns400() throws Exception {
            RegisterRequest req = createRegisterRequest("testuser", "password123", "");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(req)))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("AC13: displayName over 100 chars returns 400")
        void register_displayNameTooLong_returns400() throws Exception {
            String longName = "a".repeat(101);
            RegisterRequest req = createRegisterRequest("testuser", "password123", longName);

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(req)))
                    .andExpect(status().isBadRequest());
        }

        // ========== AC14: Username Special Characters ==========

        @Test
        @DisplayName("AC14: username with special chars returns 400")
        void register_usernameWithSpecialChars_returns400() throws Exception {
            RegisterRequest req = createRegisterRequest("test@user!", "password123", "Test User");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(req)))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("AC14: username with spaces returns 400")
        void register_usernameWithSpaces_returns400() throws Exception {
            RegisterRequest req = createRegisterRequest("test user", "password123", "Test User");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(req)))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("username with underscores is valid (alphanumeric+underscore)")
        void register_usernameWithUnderscore_returns201() throws Exception {
            RegisterRequest req = createRegisterRequest("test_user_1", "password123", "Test User");

            mockMvc.perform(post("/api/auth/register")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(req)))
                    .andExpect(status().isCreated());
        }
    }

    // ========== Login Tests ==========

    @Nested
    @DisplayName("POST /api/auth/login")
    class LoginTests {

        @Test
        @DisplayName("AC4: login with correct credentials returns 200 with token and expiresIn=86400")
        void login_validCredentials_returns200WithToken() throws Exception {
            createAndSaveUser("testuser", "password123", "Test User");

