        void login_tokenIsValidJwt() throws Exception {
            User user = createAndSaveUser("testuser", "password123", "Test User");

            LoginRequest req = createLoginRequest("testuser", "password123");

            String response = mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(req)))
                    .andExpect(status().isOk())
                    .andReturn().getResponse().getContentAsString();

            String token = objectMapper.readTree(response).get("token").asText();
            assertTrue(jwtUtil.validateToken(token));
            assertEquals(user.getId(), jwtUtil.getUserIdFromToken(token));
        }

