        @Test
        @DisplayName("BR7: wrong password and non-existent user return identical error structure (prevent enumeration)")
        void login_errorMessagesAreIdentical_preventEnumeration() throws Exception {
            createAndSaveUser("testuser", "password123", "Test User");

            // Wrong password
            LoginRequest wrongPwd = createLoginRequest("testuser", "wrongpassword");
            String wrongPwdResponse = mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(wrongPwd)))
                    .andExpect(status().isUnauthorized())
                    .andReturn().getResponse().getContentAsString();

            // Non-existent user
            LoginRequest noUser = createLoginRequest("nonexistent", "password123");
            String noUserResponse = mockMvc.perform(post("/api/auth/login")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(objectMapper.writeValueAsString(noUser)))
                    .andExpect(status().isUnauthorized())
                    .andReturn().getResponse().getContentAsString();

