import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.test.web.servlet.MvcResult;

import static org.hamcrest.Matchers.*;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@SpringBootTest
@AutoConfigureMockMvc
class TaskStatusControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private TaskRepository taskRepository;

    private String token;
    private Long taskId;

    @BeforeEach
    void setUp() throws Exception {
        taskRepository.deleteAll();
        userRepository.deleteAll();

        // Register user
        RegisterRequest regReq = new RegisterRequest();
        regReq.setUsername("stateuser");
        regReq.setPassword("password123");
        regReq.setDisplayName("State Test User");

        mockMvc.perform(post("/api/auth/register")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(regReq)))
                .andExpect(status().isCreated());

        // Login to get token
        LoginRequest loginReq = new LoginRequest();
        loginReq.setUsername("stateuser");
        loginReq.setPassword("password123");

        MvcResult loginResult = mockMvc.perform(post("/api/auth/login")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(loginReq)))
                .andExpect(status().isOk())
                .andReturn();

        token = objectMapper.readTree(loginResult.getResponse().getContentAsString())
                .get("token").asText();

        // Create a task (initial status = TODO)
        String taskJson = "{\"title\":\"State Machine Test Task\",\"priority\":\"MEDIUM\"}";

        MvcResult taskResult = mockMvc.perform(post("/api/tasks")
                        .header("Authorization", "Bearer " + token)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(taskJson))
                .andExpect(status().isCreated())
                .andReturn();

        taskId = objectMapper.readTree(taskResult.getResponse().getContentAsString())
                .get("id").asLong();
    }

    private Long createFreshTask() throws Exception {
        String taskJson = "{\"title\":\"Fresh Task " + System.nanoTime() + "\",\"priority\":\"LOW\"}";
        MvcResult result = mockMvc.perform(post("/api/tasks")
                        .header("Authorization", "Bearer " + token)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(taskJson))
                .andExpect(status().isCreated())
                .andReturn();
        return objectMapper.readTree(result.getResponse().getContentAsString())
                .get("id").asLong();
    }

    private void transitionTo(Long id, String status) throws Exception {
        String body = "{\"status\":\"" + status + "\"}";
        mockMvc.perform(patch("/api/tasks/" + id + "/status")
                        .header("Authorization", "Bearer " + token)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(body))
                .andExpect(status().isOk());
    }

    // ========== AC1: New task initial status = TODO ==========

    @Nested
    @DisplayName("AC1: Initial Status")
    class InitialStatusTests {

        @Test
        @DisplayName("AC1: newly created task has status TODO")
        void newTask_hasTodoStatus() throws Exception {
            mockMvc.perform(get("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.status").value("TODO"));
        }
    }

    // ========== AC2-AC5: Legal Transitions ==========

    @Nested
    @DisplayName("Legal Transitions (AC2-AC5)")
    class LegalTransitionTests {

        @Test
        @DisplayName("AC2: TODO -> IN_PROGRESS returns 200")
        void todoToInProgress_returns200() throws Exception {
            String body = "{\"status\":\"IN_PROGRESS\"}";

            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.status").value("IN_PROGRESS"))
                    .andExpect(jsonPath("$.id").value(taskId));
        }

        @Test
        @DisplayName("AC3: IN_PROGRESS -> TODO returns 200")
        void inProgressToTodo_returns200() throws Exception {
            // First move to IN_PROGRESS
            transitionTo(taskId, "IN_PROGRESS");

            // Then back to TODO
            String body = "{\"status\":\"TODO\"}";
            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.status").value("TODO"));
        }

        @Test
        @DisplayName("AC4: IN_PROGRESS -> DONE returns 200")
        void inProgressToDone_returns200() throws Exception {
            transitionTo(taskId, "IN_PROGRESS");

            String body = "{\"status\":\"DONE\"}";
            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.status").value("DONE"));
        }

        @Test
        @DisplayName("AC5: DONE -> CLOSED returns 200")
        void doneToClosed_returns200() throws Exception {
            transitionTo(taskId, "IN_PROGRESS");
            transitionTo(taskId, "DONE");

            String body = "{\"status\":\"CLOSED\"}";
            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.status").value("CLOSED"));
        }
    }

    // ========== AC6-AC9: Illegal Transitions ==========

    @Nested
    @DisplayName("Illegal Transitions (AC6-AC9)")
    class IllegalTransitionTests {

        @Test
        @DisplayName("AC6: TODO -> DONE returns 400 (illegal)")
        void todoToDone_returns400() throws Exception {
            String body = "{\"status\":\"DONE\"}";

            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isBadRequest())
                    .andExpect(jsonPath("$.message").isString())
                    .andExpect(jsonPath("$.timestamp").isString());
        }

        @Test
        @DisplayName("AC7: CLOSED -> any returns 400 (terminal)")
        void closedToAny_returns400() throws Exception {
            // Move to CLOSED: TODO -> IN_PROGRESS -> DONE -> CLOSED
            transitionTo(taskId, "IN_PROGRESS");
            transitionTo(taskId, "DONE");
            transitionTo(taskId, "CLOSED");

            // Try CLOSED -> TODO
            String body1 = "{\"status\":\"TODO\"}";
            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body1))
                    .andExpect(status().isBadRequest())
                    .andExpect(jsonPath("$.message").isString());

            // Try CLOSED -> IN_PROGRESS
            String body2 = "{\"status\":\"IN_PROGRESS\"}";
            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body2))
                    .andExpect(status().isBadRequest());

            // Try CLOSED -> DONE
            String body3 = "{\"status\":\"DONE\"}";
            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body3))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("AC8: TODO -> CLOSED returns 400")
        void todoToClosed_returns400() throws Exception {
            String body = "{\"status\":\"CLOSED\"}";

            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isBadRequest())
                    .andExpect(jsonPath("$.message").isString())
                    .andExpect(jsonPath("$.timestamp").isString());
        }

        @Test
        @DisplayName("AC9: DONE -> TODO returns 400")
        void doneToTodo_returns400() throws Exception {
            transitionTo(taskId, "IN_PROGRESS");
            transitionTo(taskId, "DONE");

            String body = "{\"status\":\"TODO\"}";
            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isBadRequest())
                    .andExpect(jsonPath("$.message").isString())
                    .andExpect(jsonPath("$.timestamp").isString());
        }

        @Test
        @DisplayName("AC9 extra: DONE -> IN_PROGRESS returns 400")
        void doneToInProgress_returns400() throws Exception {
            transitionTo(taskId, "IN_PROGRESS");
            transitionTo(taskId, "DONE");

            String body = "{\"status\":\"IN_PROGRESS\"}";
            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("IN_PROGRESS -> CLOSED returns 400 (must go through DONE)")
        void inProgressToClosed_returns400() throws Exception {
            transitionTo(taskId, "IN_PROGRESS");

            String body = "{\"status\":\"CLOSED\"}";
            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("Transition to same status is a no-op or error")
        void sameStatus_todoToTodo() throws Exception {
            String body = "{\"status\":\"TODO\"}";
            // Transitioning to same status should either be 200 (no-op) or 400;
            // the key thing is it doesn't break. We accept both as valid behavior.
            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                    .header("Authorization", "Bearer " + token)
                    .contentType(MediaType.APPLICATION_JSON)
                    .content(body));
            // No assertion on status code — just verifying no 500
        }
    }

    // ========== AC10: updatedAt ==========

    @Nested
    @DisplayName("AC10: updatedAt on transition")
    class UpdatedAtTests {

        @Test
        @DisplayName("AC10: successful transition updates updatedAt")
        void successfulTransition_updatesTimestamp() throws Exception {
            // Get initial task — updatedAt should be null for a fresh task
            MvcResult before = mockMvc.perform(get("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andReturn();

            String updatedAtBefore = objectMapper.readTree(
                    before.getResponse().getContentAsString()).path("updatedAt").asText(null);

            // Transition TODO -> IN_PROGRESS
            String body = "{\"status\":\"IN_PROGRESS\"}";
            MvcResult after = mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isOk())
                    .andReturn();

            JsonNode afterNode = objectMapper.readTree(after.getResponse().getContentAsString());
            String updatedAtAfter = afterNode.path("updatedAt").asText(null);

            // updatedAt should now be set (non-null)
            org.junit.jupiter.api.Assertions.assertNotNull(updatedAtAfter,
                    "updatedAt should be set after transition");
            org.junit.jupiter.api.Assertions.assertFalse(updatedAtAfter.isEmpty(),
                    "updatedAt should not be empty after transition");
        }

        @Test
        @DisplayName("AC10: failed transition does NOT update updatedAt")
        void failedTransition_doesNotUpdateTimestamp() throws Exception {
            // Get initial task
            MvcResult before = mockMvc.perform(get("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andReturn();

            String updatedAtBefore = objectMapper.readTree(
                    before.getResponse().getContentAsString()).path("updatedAt").asText(null);

            // Attempt illegal transition TODO -> DONE (should fail 400)
            String body = "{\"status\":\"DONE\"}";
            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isBadRequest());

            // Verify updatedAt unchanged
            MvcResult after = mockMvc.perform(get("/api/tasks/" + taskId)
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andReturn();

            String updatedAtAfter = objectMapper.readTree(
                    after.getResponse().getContentAsString()).path("updatedAt").asText(null);

            org.junit.jupiter.api.Assertions.assertEquals(updatedAtBefore, updatedAtAfter,
                    "updatedAt should not change on failed transition");
        }
    }

    // ========== AC11-AC14: GET transitions ==========

    @Nested
    @DisplayName("GET /api/tasks/{id}/transitions (AC11-AC14)")
    class TransitionsEndpointTests {

        @Test
        @DisplayName("AC11: GET transitions for TODO -> [IN_PROGRESS]")
        void todoTransitions() throws Exception {
            mockMvc.perform(get("/api/tasks/" + taskId + "/transitions")
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.currentStatus").value("TODO"))
                    .andExpect(jsonPath("$.availableTransitions", hasSize(1)))
                    .andExpect(jsonPath("$.availableTransitions[0]").value("IN_PROGRESS"));
        }

        @Test
        @DisplayName("AC12: GET transitions for IN_PROGRESS -> [TODO, DONE]")
        void inProgressTransitions() throws Exception {
            transitionTo(taskId, "IN_PROGRESS");

            mockMvc.perform(get("/api/tasks/" + taskId + "/transitions")
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.currentStatus").value("IN_PROGRESS"))
                    .andExpect(jsonPath("$.availableTransitions", hasSize(2)))
                    .andExpect(jsonPath("$.availableTransitions",
                            containsInAnyOrder("TODO", "DONE")));
        }

        @Test
        @DisplayName("AC13: GET transitions for DONE -> [CLOSED]")
        void doneTransitions() throws Exception {
            transitionTo(taskId, "IN_PROGRESS");
            transitionTo(taskId, "DONE");

            mockMvc.perform(get("/api/tasks/" + taskId + "/transitions")
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.currentStatus").value("DONE"))
                    .andExpect(jsonPath("$.availableTransitions", hasSize(1)))
                    .andExpect(jsonPath("$.availableTransitions[0]").value("CLOSED"));
        }

        @Test
        @DisplayName("AC14: GET transitions for CLOSED -> []")
        void closedTransitions() throws Exception {
            transitionTo(taskId, "IN_PROGRESS");
            transitionTo(taskId, "DONE");
            transitionTo(taskId, "CLOSED");

            mockMvc.perform(get("/api/tasks/" + taskId + "/transitions")
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.currentStatus").value("CLOSED"))
                    .andExpect(jsonPath("$.availableTransitions", hasSize(0)));
        }
    }

    // ========== AC15: No token -> 401 ==========

    @Nested
    @DisplayName("AC15: Unauthorized (no token)")
    class UnauthorizedTests {

        @Test
        @DisplayName("AC15: PATCH status without token returns 401")
        void patchStatus_noToken_returns401() throws Exception {
            String body = "{\"status\":\"IN_PROGRESS\"}";

            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("AC15: GET transitions without token returns 401")
        void getTransitions_noToken_returns401() throws Exception {
            mockMvc.perform(get("/api/tasks/" + taskId + "/transitions"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("AC15: PATCH status with invalid token returns 401")
        void patchStatus_invalidToken_returns401() throws Exception {
            String body = "{\"status\":\"IN_PROGRESS\"}";

            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer invalid.token.here")
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isUnauthorized());
        }
    }

    // ========== AC16: Non-existent task -> 404 ==========

    @Nested
    @DisplayName("AC16: Not Found (non-existent task)")
    class NotFoundTests {

        @Test
        @DisplayName("AC16: PATCH status for non-existent task returns 404")
        void patchStatus_nonExistentTask_returns404() throws Exception {
            String body = "{\"status\":\"IN_PROGRESS\"}";

            mockMvc.perform(patch("/api/tasks/999999/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isNotFound())
                    .andExpect(jsonPath("$.message").isString())
                    .andExpect(jsonPath("$.timestamp").isString());
        }

        @Test
        @DisplayName("AC16: GET transitions for non-existent task returns 404")
        void getTransitions_nonExistentTask_returns404() throws Exception {
            mockMvc.perform(get("/api/tasks/999999/transitions")
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isNotFound())
                    .andExpect(jsonPath("$.message").isString())
                    .andExpect(jsonPath("$.timestamp").isString());
        }
    }

    // ========== Response Format ==========

    @Nested
    @DisplayName("Response Format")
    class ResponseFormatTests {

        @Test
        @DisplayName("Successful PATCH returns full TaskResponse")
        void successfulPatch_returnsTaskResponse() throws Exception {
            String body = "{\"status\":\"IN_PROGRESS\"}";

            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
                            .header("Authorization", "Bearer " + token)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.id").value(taskId))
                    .andExpect(jsonPath("$.title").value("State Machine Test Task"))
                    .andExpect(jsonPath("$.status").value("IN_PROGRESS"))
                    .andExpect(jsonPath("$.priority").value("MEDIUM"))
                    .andExpect(jsonPath("$.createdAt").isString());
        }

        @Test
        @DisplayName("GET transitions returns currentStatus and availableTransitions")
        void getTransitions_returnsCorrectShape() throws Exception {
            mockMvc.perform(get("/api/tasks/" + taskId + "/transitions")
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.currentStatus").isString())
                    .andExpect(jsonPath("$.availableTransitions").isArray());
        }
    }

    // ========== Full Lifecycle ==========

    @Nested
    @DisplayName("Full Lifecycle")
    class FullLifecycleTests {

        @Test
        @DisplayName("Complete lifecycle: TODO -> IN_PROGRESS -> DONE -> CLOSED")
        void fullLifecycle() throws Exception {
            Long freshId = createFreshTask();

            // TODO -> IN_PROGRESS
            transitionTo(freshId, "IN_PROGRESS");
            mockMvc.perform(get("/api/tasks/" + freshId)
                            .header("Authorization", "Bearer " + token))
                    .andExpect(jsonPath("$.status").value("IN_PROGRESS"));

            // IN_PROGRESS -> DONE
            transitionTo(freshId, "DONE");
            mockMvc.perform(get("/api/tasks/" + freshId)
                            .header("Authorization", "Bearer " + token))
                    .andExpect(jsonPath("$.status").value("DONE"));

            // DONE -> CLOSED
            transitionTo(freshId, "CLOSED");
            mockMvc.perform(get("/api/tasks/" + freshId)
                            .header("Authorization", "Bearer " + token))
                    .andExpect(jsonPath("$.status").value("CLOSED"));
        }

        @Test
        @DisplayName("Bounce lifecycle: TODO -> IN_PROGRESS -> TODO -> IN_PROGRESS -> DONE -> CLOSED")
        void bounceLifecycle() throws Exception {
            Long freshId = createFreshTask();

            transitionTo(freshId, "IN_PROGRESS");
            transitionTo(freshId, "TODO");
            transitionTo(freshId, "IN_PROGRESS");
            transitionTo(freshId, "DONE");
            transitionTo(freshId, "CLOSED");

            mockMvc.perform(get("/api/tasks/" + freshId)
                            .header("Authorization", "Bearer " + token))
                    .andExpect(jsonPath("$.status").value("CLOSED"));
        }
    }
}

